#!/usr/bin/env python3
import base64
import zlib
import sys
try:
    from Crypto.Cipher import AES
    from Crypto.Util.Padding import unpad
except ImportError:
    print("错误：缺少 pycryptodome 库，请执行以下命令安装：")
    print("pip install pycryptodome")
    sys.exit(1)
obfuscated_key = b"2\x87\xe61 \x105\xe6\xef\x80f\xdc\x06'\xf9.\xd7I\xfb\xbdR\xcf\xa3\xb4\xc0\xffot\x07\xf3\xab\xe9"
final_b64 = ""
key = bytes([b ^ 170 for b in obfuscated_key])
try:
    compressed = base64.b64decode(final_b64)
    b64_data = zlib.decompress(compressed)
    iv_ciphertext = base64.b64decode(b64_data)
    iv = iv_ciphertext[:16]
    ciphertext = iv_ciphertext[16:]
    cipher = AES.new(key, AES.MODE_CBC, iv)
    plaintext = unpad(cipher.decrypt(ciphertext), AES.block_size)
except Exception as e:
    print("自解密失败：", e)
    sys.exit(1)
exec_globals = {
    '__name__': __name__,
    '__file__': __file__,
    '__package__': __package__,
    '__doc__': __doc__,
}
try:
    exec(plaintext.decode('utf-8'), exec_globals)
except Exception as e:
    print("执行原始代码时出错：", e)
    sys.exit(1)
